    15→package browserapi
    16→
    17→import (
    18→	"sync"
    19→
    20→	"github.com/unstablebuild/rune-go-sdk/handler"
    21→	"github.com/unstablebuild/rune-go-sdk/term"
    22→	"github.com/unstablebuild/rune-go-sdk/tui"
    23→)
    24→
    25→// FuncHandler returns a Handler by wrapping a tui.Handler
    26→// with an Close callback.
    27→func FuncHandler(h tui.Handler, doClose func() error) Handler {
    28→	return &closeHandler{Handler: h, doClose: doClose}
    29→}
    30→
    31→// NopHandler returns a Handler by wrapping a tui.Handler
    32→// with an nop Close callback.
    33→func NopHandler(h tui.Handler) Handler {
    34→	return &closeHandler{Handler: h, doClose: func() error { return nil }}
    35→}
    36→
    37→// SyncHandler wraps the given handler and adds synchronized access.
    38→func SyncHandler(locker sync.Locker, h Handler) Handler {
    39→	return &syncHandler{handler: h, locker: locker}
    40→}
    41→
    42→// StaticFloating wraps a Handler and returns a Floating that always
    43→// return the same Dimensions values.
    44→func StaticFloating(h Handler, width, height int) Floating {
    45→	return staticFloating{width: width, height: height, Handler: h}
    46→}
    47→
    48→// NopFloatingHandler wraps a handler.Floating and returns a Floating
    49→// that does nothing when Close is called.
    50→func NopFloatingHandler(h handler.Floating) Floating {
    51→	return nopFloating{Floating: h}
    52→}
    53→
    54→// FuncFloatingHandler wraps a handler.Floating and returns a Floating
    55→// that calls calls closeFn when Close is called.
    56→func FuncFloatingHandler(h handler.Floating, closeFn func() error) Floating {
    57→	return funcFloatingHandler{Floating: h, fn: closeFn}
    58→}
    59→
    60→// FuncFloating wraps a Handler and returns a Floating that
    61→// calls dimFn when Dimensions is called.
    62→func FuncFloating(h Handler, dimFn func() (int, int)) Floating {
    63→	return funcFloating{Handler: h, fn: dimFn}
    64→}
    65→
    66→type funcFloatingHandler struct {
    67→	handler.Floating
    68→	fn func() error
    69→}
    70→
    71→func (f funcFloatingHandler) Close() error {
    72→	return f.fn()
    73→}
    74→
    75→type funcFloating struct {
    76→	Handler
    77→	fn func() (int, int)
    78→}
    79→
    80→func (f funcFloating) Dimensions() (width, height int) {
    81→	return f.fn()
    82→}
    83→
    84→type closeHandler struct {
    85→	tui.Handler
    86→	doClose func() error
    87→}
    88→
    89→func (h *closeHandler) Close() error {
    90→	return h.doClose()
    91→}
    92→
    93→type staticFloating struct {
    94→	Handler
    95→	width, height int
    96→}
    97→
    98→func (s staticFloating) Dimensions() (int, int) {
    99→	return s.width, s.height
   100→}
   101→
   102→type nopFloating struct {
   103→	handler.Floating
   104→}
   105→
   106→func (n nopFloating) Close() error {
   107→	return nil
   108→
   109→}
