   111→type syncHandler struct {
   112→	locker  sync.Locker
   113→	handler Handler
   114→}
   115→
   116→func (s syncHandler) Resize(width, height int) {
   117→	s.locker.Lock()
   118→	defer s.locker.Unlock()
   119→	s.handler.Resize(width, height)
   120→}
   121→
   122→func (s syncHandler) Draw(w term.Writer) {
   123→	s.locker.Lock()
   124→	defer s.locker.Unlock()
   125→	s.handler.Draw(w)
   126→}
   127→
   128→func (s syncHandler) Handle(ev term.Event) (exit, handled bool) {
   129→	s.locker.Lock()
   130→	defer s.locker.Unlock()
   131→	return s.handler.Handle(ev)
   132→}
   133→
   134→func (s syncHandler) Cursor() (c term.Coordinates, style term.CursorStyle, show bool) {
   135→	s.locker.Lock()
   136→	defer s.locker.Unlock()
   137→	return s.handler.Cursor()
   138→}
   139→
   140→func (s syncHandler) Selection() (string, bool) {
   141→	s.locker.Lock()
   142→	defer s.locker.Unlock()
   143→	return s.handler.Selection()
   144→}
   145→
   146→func (s syncHandler) Close() error {
   147→	s.locker.Lock()
   148→	defer s.locker.Unlock()
   149→	return s.handler.Close()
   150→}
