    15→package retry
    16→
    17→import (
    18→	"context"
    19→	"errors"
    20→	"math"
    21→	"time"
    22→)
    23→
    24→// Strategy represents a retry strategy. See Retry for more details.
    25→type Strategy func(count uint) (sleep time.Duration, stop bool)
    26→
    27→// DefaultStrategy returns an exponential backoff strategy with a limit of 10, a min sleep
    28→// time of 1ms and a max sleep time of 1024ms. At most, this strategy yields a retry mechanism
    29→// that can last approximately 2 seconds.
    30→var DefaultStrategy Strategy = CombinedStrategy(
    31→	LimitStrategy(10), ExponentialStrategy(1*time.Millisecond, 1024*time.Millisecond))
    32→
    33→// LimitStrategy returns a retry strategy that stops after limit number of retries
    34→// has been reached.
    35→func LimitStrategy(limit uint) Strategy {
    36→	return func(count uint) (sleep time.Duration, stop bool) {
    37→		return 0, count >= limit
    38→	}
    39→}
    40→
    41→// ExponentialStrategy returns a retry strategy that never stops but increments
    42→// the sleep time from min to max in power of 2 increments.
    43→func ExponentialStrategy(min, max time.Duration) Strategy {
    44→	return func(count uint) (sleep time.Duration, stop bool) {
    45→		sleep = time.Duration(math.Pow(2, float64(count-1))) * min
    46→		if sleep > max {
    47→			sleep = max
    48→		}
    49→		return
    50→	}
    51→}
    52→
    53→// SequentialStrategy returns a retry strategy that never stops and retries
    54→// always after 'every' duration.
    55→func SequentialStrategy(every time.Duration) Strategy {
    56→	return func(count uint) (sleep time.Duration, stop bool) {
    57→		sleep = every
    58→		return
    59→	}
    60→}
    61→
    62→// CombinedStrategy returns a retry strategy that combines all the given strategies
    63→// using the following rules:
    64→//   - If any returns stop=true, then stop=true is returned.
    65→//   - If multiple return a sleep time that is non-zero, then the biggest sleep value is used.
    66→func CombinedStrategy(i Strategy, n ...Strategy) Strategy {
    67→	all := append([]Strategy{}, i)
    68→	all = append(all, n...)
    69→	return func(count uint) (sleep time.Duration, stop bool) {
    70→		var max time.Duration
    71→		for _, strategy := range all {
    72→			sleep, stop = strategy(count)
    73→			if stop {
    74→				return
    75→			}
    76→			if sleep > max {
    77→				max = sleep
    78→			}
    79→		}
    80→		return max, false
    81→	}
    82→}
    83→
    84→// Retry retries the given function with the given Strategy, until function returns
    85→// no error, strategy returns stop=true, function returns error and retry=false,
    86→// or ctx deadline is exceeded.
    87→func Retry(
    88→	ctx context.Context, strategy Strategy,
    89→	fn func(ctx context.Context) (shouldRetry bool, err error),
    90→) error {
    91→	var retryCount uint
    92→	var result error
    93→	for {
    94→		retry, err := fn(ctx)
    95→		if err == nil {
    96→			return nil
    97→		}
    98→		if !retry {
    99→			// if we never allowed retries, pass error as is
   100→			if result == nil {
   101→				return err
   102→			}
   103→			return errors.Join(result, err)
   104→		}
   105→		result = errors.Join(result, err)
   106→
   107→		retryCount++
   108→		sleep, stop := strategy(retryCount)
   109→		if stop {
   110→			return result
   111→		}
   112→		// short-circuit if context is cancel
   113→		// proceed to wait if it's not
   114→		select {
   115→		case <-ctx.Done():
   116→			// don't pollute the results with extra context errors
   117→			if !errors.Is(result, context.DeadlineExceeded) &&
   118→				!errors.Is(result, context.Canceled) {
   119→				result = errors.Join(result, ctx.Err())
   120→			}
   121→			return result
   122→		default:
   123→		}
   124→		select {
   125→		case <-ctx.Done():
   126→			result = errors.Join(result, ctx.Err())
   127→			return result
   128→		case <-time.After(sleep):
   129→		}
   130→	}
   131→}
   132→

