func (g *goplsLSP) locationRequest(ctx context.Context, method string, params any) ([]semanticapi.Location, error) {
	var raw json.RawMessage
	if err := g.conn.call(ctx, method, params, &raw); err != nil {
		return nil, err
	}
	if raw == nil || string(raw) == "null" {
		return nil, nil
	}
	// gopls may return a single Location or []Location.
	var locs []semanticapi.Location
	if err := json.Unmarshal(raw, &locs); err != nil {
		var single semanticapi.Location
		if err2 := json.Unmarshal(raw, &single); err2 != nil {
			return nil, err
		}
		locs = []semanticapi.Location{single}
	}
	return locs, nil
}

