package idelsp

import (
	"bufio"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"strconv"
	"strings"
	"sync"
)

// RPCError represents an error returned by a JSON-RPC server.
type RPCError struct {
	Code    int    `json:"code"`
	Message string `json:"message"`
}

// Error implements the error interface.
func (e *RPCError) Error() string {
	return fmt.Sprintf("rpc error %d: %s", e.Code, e.Message)
}

type jsonrpcMessage struct {
	JSONRPC string          `json:"jsonrpc"`
	ID      *int            `json:"id,omitempty"`
	Method  string          `json:"method,omitempty"`
	Params  json.RawMessage `json:"params,omitempty"`
	Result  json.RawMessage `json:"result,omitempty"`
	Error   *RPCError       `json:"error,omitempty"`
}

type rpcConn struct {
	mu      sync.Mutex
	nextID  int
	stdin   io.WriteCloser
	pending map[int]chan jsonrpcMessage
	done    chan struct{}
	readErr error
}

func newRPCConn(
	stdin io.WriteCloser, stdout io.ReadCloser,
) *rpcConn {
	c := &rpcConn{
		stdin:   stdin,
		pending: make(map[int]chan jsonrpcMessage),
		done:    make(chan struct{}),
	}
	go c.readLoop(stdout)
	return c
}

func (c *rpcConn) readLoop(r io.Reader) {
	br := bufio.NewReader(r)
	for {
		var contentLen int
		for {
			line, err := br.ReadString('\n')
			if err != nil {
				c.mu.Lock()
				c.readErr = err
				for _, ch := range c.pending {
					close(ch)
				}
				c.mu.Unlock()
				close(c.done)
				return
			}
			line = strings.TrimSpace(line)
			if line == "" {
				break
			}
			if strings.HasPrefix(line, "Content-Length:") {
				val := strings.TrimSpace(
					strings.TrimPrefix(line, "Content-Length:"),
				)
				contentLen, _ = strconv.Atoi(val)
			}
		}
		if contentLen == 0 {
			continue
		}

		body := make([]byte, contentLen)
		if _, err := io.ReadFull(br, body); err != nil {
			c.mu.Lock()
			c.readErr = err
			for _, ch := range c.pending {
				close(ch)
			}
			c.mu.Unlock()
			close(c.done)
			return
		}

		var msg jsonrpcMessage
		if err := json.Unmarshal(body, &msg); err != nil {
			continue
		}

		// Response to a request we sent.
		if msg.ID != nil && msg.Method == "" {
			c.mu.Lock()
			ch, ok := c.pending[*msg.ID]
			if ok {
				delete(c.pending, *msg.ID)
			}
			c.mu.Unlock()
			if ok {
				ch <- msg
			}
		}
		// Server-initiated notifications (msg.ID == nil)
		// are silently ignored.
	}
}

func (c *rpcConn) call(
	ctx context.Context, method string,
	params, result any,
) error {
	c.mu.Lock()
	id := c.nextID
	c.nextID++
	ch := make(chan jsonrpcMessage, 1)
	c.pending[id] = ch
	c.mu.Unlock()

	paramBytes, err := json.Marshal(params)
	if err != nil {
		return err
	}
	req := jsonrpcMessage{
		JSONRPC: "2.0",
		ID:      &id,
		Method:  method,
		Params:  paramBytes,
	}
	body, err := json.Marshal(req)
	if err != nil {
		return err
	}
	header := fmt.Sprintf(
		"Content-Length: %d\r\n\r\n", len(body),
	)

	c.mu.Lock()
	_, err = io.WriteString(c.stdin, header)
	if err == nil {
		_, err = c.stdin.Write(body)
	}
	c.mu.Unlock()
	if err != nil {
		return err
	}

	select {
	case <-ctx.Done():
		return ctx.Err()
	case msg, ok := <-ch:
		if !ok {
			return fmt.Errorf(
				"connection closed: %v", c.readErr,
			)
		}
		if msg.Error != nil {
			return msg.Error
		}
		if result != nil && msg.Result != nil {
			return json.Unmarshal(msg.Result, result)
		}
		return nil
	}
}

func (c *rpcConn) notify(
	ctx context.Context, method string, params any,
) error {
	paramBytes, err := json.Marshal(params)
	if err != nil {
		return err
	}
	req := jsonrpcMessage{
		JSONRPC: "2.0",
		Method:  method,
		Params:  paramBytes,
	}
	body, err := json.Marshal(req)
	if err != nil {
		return err
	}
	header := fmt.Sprintf(
		"Content-Length: %d\r\n\r\n", len(body),
	)

	c.mu.Lock()
	defer c.mu.Unlock()
	if _, err := io.WriteString(c.stdin, header); err != nil {
		return err
	}
	_, err = c.stdin.Write(body)
	return err
}

func (c *rpcConn) close() error {
	err := c.stdin.Close()
	<-c.done
	return err
}

