					},
					"formats": []string{"relative"},
				},
			},
			"workspace": map[string]any{
				"symbol": map[string]any{},
			},
		},
	}

	var raw json.RawMessage
	if err := s.conn.call(
		ctx, "initialize", p, &raw,
	); err != nil {
		return err
	}

	return s.conn.notify(ctx, "initialized", struct{}{})
}

func (s *langServer) stop(ctx context.Context) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if !s.alive {
		return nil
	}
	s.alive = false
	_ = s.conn.call(ctx, "shutdown", nil, nil)
	_ = s.conn.notify(ctx, "exit", nil)
	return s.conn.close()
}

func (s *langServer) call(
	ctx context.Context, method string,
	params, result any,
) error {
	s.mu.Lock()
	if !s.alive {
		s.mu.Unlock()
		return ErrNoServer
	}
	conn := s.conn
	s.mu.Unlock()
	return conn.call(ctx, method, params, result)
}

func (s *langServer) notify(
	ctx context.Context, method string, params any,
) error {
	s.mu.Lock()
	if !s.alive {
		s.mu.Unlock()
		return ErrNoServer
	}
	conn := s.conn
	s.mu.Unlock()
	return conn.notify(ctx, method, params)
}

