package idelsp

import (
	"context"
	"errors"
	"fmt"
	"log/slog"
	"path/filepath"
	"sync"
	"time"

	"github.com/unstablebuild/rune-go-sdk/api/browserapi"
	"github.com/unstablebuild/rune-go-sdk/api/semanticapi"
	"github.com/unstablebuild/rune-go-sdk/api/textapi"
	"github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
	"github.com/unstablebuild/rune-go-sdk/iterator"
	"github.com/unstablebuild/rune-go-sdk/retry"
)

// ErrNoServer is returned when no language server is
// available for the requested file.
var ErrNoServer = errors.New("no language server")

// Config configures a Manager.
type Config struct {
	RootURI       string
	FileSystem    workspaceapi.FileSystem
	Executor      workspaceapi.Executor
	Notifications browserapi.Notifications
	PkgManager    PkgManager
	MaxRetries    uint
}

// Manager is a multi-language LSP server manager.
// It implements semanticapi.LSP and textapi.EventHandler.
type Manager struct {
	mu         sync.Mutex
	cfg        Config
	servers    map[string]*langServer
	fileToLang map[string]string
	ctx        context.Context
	cancel     context.CancelFunc
}

var (
	_ semanticapi.LSP    = (*Manager)(nil)
	_ textapi.EventHandler = (*Manager)(nil)
)

// New creates a new Manager with the given configuration.
func New(cfg Config) *Manager {
	if cfg.MaxRetries == 0 {
		cfg.MaxRetries = 3
	}
	ctx, cancel := context.WithCancel(context.Background())
	return &Manager{
		cfg:        cfg,
		servers:    make(map[string]*langServer),
		fileToLang: make(map[string]string),
		ctx:        ctx,
		cancel:     cancel,
	}
}

// Close shuts down all active language servers.
func (m *Manager) Close() error {
	m.cancel()
	m.mu.Lock()
	servers := make([]*langServer, 0, len(m.servers))
	for _, s := range m.servers {
		servers = append(servers, s)
	}
	m.mu.Unlock()

	var errs []error
	ctx, cancel := context.WithTimeout(
		context.Background(), 5*time.Second,
	)
	defer cancel()
	for _, s := range servers {
		if err := s.stop(ctx); err != nil {
			errs = append(errs, err)
		}
	}
	return errors.Join(errs...)
}

// Handle implements textapi.EventHandler.
func (m *Manager) Handle(
	ctx context.Context, ev textapi.Event,
) bool {
	uri := ev.URI.String()

	switch ev.Type {
	case textapi.EventTypeOpen:
		ext := filepath.Ext(ev.URI.Path())
		srv, err := m.ensureServer(ctx, ext)
		if err != nil {
			slog.Warn("idelsp: ensure server",
				"ext", ext, "error", err)
			return false
		}
		lang := langForExt(ext)
		m.mu.Lock()
		m.fileToLang[uri] = lang.id
		m.mu.Unlock()
		_ = srv.notify(ctx, "textDocument/didOpen",
			semanticapi.DidOpenTextDocumentParams{
				TextDocument: semanticapi.TextDocumentItem{
					URI:        uri,
					LanguageID: lang.id,
					Version:    1,
					Text:       ev.Content,
				},
			})

	case textapi.EventTypeClose:
		srv, err := m.serverForURI(uri)
		if err != nil {
			return false
		}
		_ = srv.notify(ctx, "textDocument/didClose",
			semanticapi.DidCloseTextDocumentParams{
				TextDocument: semanticapi.TextDocumentIdentifier{
					URI: uri,
				},
			})

	case textapi.EventTypeEdit:
		srv, err := m.serverForURI(uri)
		if err != nil {
			return false
		}
		_ = srv.notify(ctx, "textDocument/didChange",
			semanticapi.DidChangeTextDocumentParams{
				TextDocument: semanticapi.VersionedTextDocumentIdentifier{
					URI: uri,
				},
				ContentChanges: []semanticapi.TextDocumentContentChangeEvent{
					{
						Range: &semanticapi.Range{
							Start: semanticapi.Position{
								Line:      uint32(ev.Start.Y),
								Character: uint32(ev.Start.X),
							},
							End: semanticapi.Position{
								Line:      uint32(ev.End.Y),
								Character: uint32(ev.End.X),
							},
						},
						Text: ev.Content,
					},
				},
			})

	case textapi.EventTypeFlush:
		srv, err := m.serverForURI(uri)
		if err != nil {
			return false
		}
		_ = srv.notify(ctx, "textDocument/didSave",
			semanticapi.DidSaveTextDocumentParams{
				TextDocument: semanticapi.TextDocumentIdentifier{
					URI: uri,
				},
			})

	case textapi.EventTypeCreate:
		m.broadcastNotify(ctx, "workspace/didCreateFiles",
			semanticapi.CreateFilesParams{
				Files: []semanticapi.FileCreate{
					{URI: uri},
				},
			})

	case textapi.EventTypeChange:
		m.broadcastNotify(ctx,
			"workspace/didChangeWatchedFiles",
			semanticapi.DidChangeWatchedFilesParams{
				Changes: []semanticapi.FileEvent{
					{
						URI:  uri,
						Type: semanticapi.FileChangeTypeChanged,
					},
				},
			})

	case textapi.EventTypeRemove:
		m.broadcastNotify(ctx, "workspace/didDeleteFiles",
			semanticapi.DeleteFilesParams{
				Files: []semanticapi.FileDelete{
					{URI: uri},
				},
			})

	case textapi.EventTypeRename:
		m.broadcastNotify(ctx, "workspace/didRenameFiles",
			semanticapi.RenameFilesParams{
				Files: []semanticapi.FileRename{
					{OldURI: uri, NewURI: ev.Content},
				},
			})

	default:
		return false
	}

	return false
}

func (m *Manager) ensureServer(
	ctx context.Context, ext string,
) (*langServer, error) {
	lang := langForExt(ext)
	if lang == nil {
		return nil, fmt.Errorf(
			"%w: unsupported extension %q", ErrNoServer, ext,
		)
	}

	m.mu.Lock()
	if srv, ok := m.servers[lang.id]; ok {
		m.mu.Unlock()
		return srv, nil
	}
	m.mu.Unlock()

	binPath, err := m.findBinary(ctx, lang)
	if err != nil {
		if m.cfg.Notifications != nil {
			_, _ = m.cfg.Notifications.Notify(
				browserapi.LevelError,
				"LSP server %s not found: %s",
				lang.command, err,
			)
		}
		return nil, fmt.Errorf(
			"find %s: %w", lang.command, err,
		)
	}

	srv := newLangServer(
		*lang, binPath, m.cfg.Executor, m.cfg.RootURI,
	)
	if err := srv.start(ctx); err != nil {
		if m.cfg.Notifications != nil {
			_, _ = m.cfg.Notifications.Notify(
				browserapi.LevelError,
				"Failed to start %s: %s",
				lang.command, err,
			)
		}
		return nil, err
	}

	m.mu.Lock()
	m.servers[lang.id] = srv
	m.mu.Unlock()

	go m.watchServer(lang, srv)
	return srv, nil
}

func (m *Manager) findBinary(
	ctx context.Context, lang *langConfig,
) (string, error) {
	if m.cfg.PkgManager == nil {
		return "", fmt.Errorf(
			"no PkgManager configured",
		)
	}
	dirs, err := m.cfg.PkgManager.LibDir(
		ctx, lang.pkgID,
	)
	if err != nil {
		return "", err
	}
	defer func() { _ = dirs.Close() }()

	paths, err := iterator.ToSlice(ctx, dirs)
	if err != nil {
		return "", err
	}

	for _, dir := range paths {
		candidate := filepath.Join(dir, lang.command)
		if m.cfg.FileSystem == nil {
			continue
		}
		if _, err := m.cfg.FileSystem.Stat(
			candidate,
		); err == nil {
			return candidate, nil
		}
	}
	return "", fmt.Errorf(
		"%s not found in any package directory",
		lang.command,
	)
}

func (m *Manager) watchServer(
	lang *langConfig, srv *langServer,
) {
	srv.mu.Lock()
	watcher := srv.watcher
	srv.mu.Unlock()
	if watcher == nil {
		return
	}

	ch := watcher.WatchProcess()
	if ch == nil {
		return
	}

	select {
	case <-m.ctx.Done():
		return
	case err := <-ch:
		if err == nil {
			return
		}
		slog.Warn("idelsp: server crashed",
			"language", lang.id, "error", err)
	}

	strategy := retry.CombinedStrategy(
		retry.LimitStrategy(m.cfg.MaxRetries),
		retry.ExponentialStrategy(
			500*time.Millisecond,
			5*time.Second,
		),
	)

	retryErr := retry.Retry(m.ctx, strategy,
		func(ctx context.Context) (bool, error) {
			if err := srv.start(ctx); err != nil {
				return true, err
			}
			m.reopenFiles(ctx, lang.id, srv)
			go m.watchServer(lang, srv)
			return false, nil
		})

	if retryErr != nil && m.cfg.Notifications != nil {
		_, _ = m.cfg.Notifications.Notify(
			browserapi.LevelError,
			"LSP server %s failed after %d retries: %s",
			lang.command, m.cfg.MaxRetries, retryErr,
		)
	}
}

func (m *Manager) reopenFiles(
	ctx context.Context, langID string,
	srv *langServer,
) {
	m.mu.Lock()
	var uris []string
	for uri, lid := range m.fileToLang {
		if lid == langID {
			uris = append(uris, uri)
		}
	}
	m.mu.Unlock()

	for _, uri := range uris {
		_ = srv.notify(ctx, "textDocument/didOpen",
			semanticapi.DidOpenTextDocumentParams{
				TextDocument: semanticapi.TextDocumentItem{
					URI:        uri,
					LanguageID: langID,
					Version:    1,
				},
			})
	}
}

func (m *Manager) serverForURI(
	uri string,
) (*langServer, error) {
	m.mu.Lock()
	langID, ok := m.fileToLang[uri]
	if !ok {
		m.mu.Unlock()
		return nil, fmt.Errorf(
			"%w: no server for %s", ErrNoServer, uri,
		)
	}
	srv, ok := m.servers[langID]
	m.mu.Unlock()
	if !ok {
		return nil, fmt.Errorf(
			"%w: server %s not running",
			ErrNoServer, langID,
		)
	}
	return srv, nil
}

func (m *Manager) allServers() []*langServer {
	m.mu.Lock()
	defer m.mu.Unlock()
	servers := make(
		[]*langServer, 0, len(m.servers),
	)
	for _, s := range m.servers {
		servers = append(servers, s)
	}
	return servers
}

func (m *Manager) broadcastNotify(
	ctx context.Context, method string, params any,
) {
	for _, srv := range m.allServers() {
		_ = srv.notify(ctx, method, params)
	}
}

