	ctx, cancel := context.WithCancel(context.Background())
	return &Manager{
		cfg:        cfg,
		servers:    make(map[string]*langServer),
		fileToLang: make(map[string]string),
		ctx:        ctx,
		cancel:     cancel,
	}
