// Initialize stores the root URI. Individual servers
// are started lazily on first file open.
func (m *Manager) Initialize(
	ctx context.Context,
	params semanticapi.InitializeParams,
) (semanticapi.InitializeResult, error) {
	m.mu.Lock()
	m.cfg.RootURI = params.RootURI
	m.mu.Unlock()
	return semanticapi.InitializeResult{
		Capabilities: semanticapi.ServerCapabilities{
			CompletionProvider: &semanticapi.CompletionOptions{},
			HoverProvider:              true,
			SignatureHelpProvider:      &semanticapi.SignatureHelpOptions{},
			DefinitionProvider:         true,
			DeclarationProvider:        true,
