)

type mockPkgManager struct {
	dirs []string
}

func (m *mockPkgManager) LibDir(
	_ context.Context, _ string,
) (iterator.Iterator[string], error) {
	return iterator.FromSlice(m.dirs), nil
}

type mockFileSystem struct {
	files map[string]bool
}

func (m *mockFileSystem) URI(
	path string,
) (workspaceapi.URI, error) {
	return workspaceapi.ParseURI("file://" + path)
}

func (m *mockFileSystem) Stat(
	path string,
) (os.FileInfo, error) {
	if m.files[path] {
		return nil, nil
	}
	return nil, os.ErrNotExist
}

func (m *mockFileSystem) OpenFile(
	string, int, os.FileMode,
) (workspaceapi.File, error) {
	return nil, nil
}

func (m *mockFileSystem) Remove(string) error {
	return nil
}

func (m *mockFileSystem) ReadDir(
	string,
) ([]os.DirEntry, error) {
	return nil, nil
}

func (m *mockFileSystem) MkdirAll(
	string, os.FileMode,
) error {
	return nil
}

type mockNotifications struct {
	mu       sync.Mutex
	messages []string
}

func (m *mockNotifications) Notify(
	_ browserapi.NotificationLevel,
	msg string, args ...any,
) (string, error) {
	m.mu.Lock()
	defer m.mu.Unlock()
	m.messages = append(m.messages, fmt.Sprintf(msg, args...))
	return "", nil
}

func (m *mockNotifications) NotifyOnce(
	_ browserapi.NotificationLevel,
	msg string, args ...any,
) (string, error) {
	return m.Notify(0, msg, args...)
}

func (m *mockNotifications) UpdateNotificationProgress(
	_, _ string, _, _ int64,
) error {
	return nil
}

type mockLSPServer struct {
	stdinR  *io.PipeReader
	stdoutW *io.PipeWriter
	done    chan struct{}
}

func newMockLSPServer() (
	clientStdin io.WriteCloser,
	clientStdout io.ReadCloser,
	srv *mockLSPServer,
) {
	srvStdinR, clientStdinW := io.Pipe()
	clientStdoutR, srvStdoutW := io.Pipe()
	srv = &mockLSPServer{
		stdinR:  srvStdinR,
		stdoutW: srvStdoutW,
		done:    make(chan struct{}),
	}
	go srv.serve()
	return clientStdinW, clientStdoutR, srv
}

func (s *mockLSPServer) serve() {
	defer close(s.done)
	br := bufio.NewReader(s.stdinR)
	for {
		contentLen, err := readHeaders(br)
		if err != nil {
			return
		}
		body := make([]byte, contentLen)
		if _, err := io.ReadFull(br, body); err != nil {
			return
		}
		var msg jsonrpcMessage
		if err := json.Unmarshal(body, &msg); err != nil {
			continue
		}
		if msg.ID == nil {
			continue
		}
		resp := s.handleRequest(msg)
		respBody, _ := json.Marshal(resp)
		header := fmt.Sprintf(
			"Content-Length: %d\r\n\r\n",
			len(respBody),
		)
		if _, err := io.WriteString(
			s.stdoutW, header,
		); err != nil {
			return
		}
		if _, err := s.stdoutW.Write(
			respBody,
		); err != nil {
			return
		}
	}
}

func (s *mockLSPServer) handleRequest(
	msg jsonrpcMessage,
) jsonrpcMessage {
	resp := jsonrpcMessage{
		JSONRPC: "2.0",
		ID:      msg.ID,
	}
	switch msg.Method {
	case "initialize":
		result, _ := json.Marshal(map[string]any{
			"capabilities": map[string]any{},
		})
		resp.Result = result
	case "shutdown":
		result, _ := json.Marshal(nil)
		resp.Result = result
	case "textDocument/hover":
		result, _ := json.Marshal(map[string]any{
			"contents": map[string]any{
				"kind":  "markdown",
				"value": "test hover",
			},
		})
		resp.Result = result
	case "textDocument/definition":
		result, _ := json.Marshal(
			[]semanticapi.Location{{
				URI: "file:///test/main.go",
				Range: semanticapi.Range{
					Start: semanticapi.Position{
						Line: 10, Character: 0,
					},
					End: semanticapi.Position{
						Line: 10, Character: 5,
					},
				},
			}},
		)
		resp.Result = result
	case "textDocument/references":
		result, _ := json.Marshal(
			[]semanticapi.Location{
				{
					URI: "file:///test/main.go",
					Range: semanticapi.Range{
						Start: semanticapi.Position{
							Line: 5, Character: 0,
						},
						End: semanticapi.Position{
							Line: 5, Character: 5,
						},
					},
				},
				{
					URI: "file:///test/main.go",
					Range: semanticapi.Range{
						Start: semanticapi.Position{
							Line: 15, Character: 0,
						},
						End: semanticapi.Position{
							Line: 15, Character: 5,
						},
					},
				},
			},
		)
		resp.Result = result
	case "workspace/symbol":
		result, _ := json.Marshal(
			[]semanticapi.SymbolInformation{{
				Name: "TestSymbol",
				Kind: semanticapi.SymbolKindFunction,
				Location: semanticapi.Location{
					URI: "file:///test/main.go",
				},
			}},
		)
		resp.Result = result
	case "textDocument/completion":
		result, _ := json.Marshal(map[string]any{
			"isIncomplete": false,
			"items": []map[string]any{{
				"label": "TestFunc",
				"kind":  3,
			}},
		})
		resp.Result = result
	default:
		result, _ := json.Marshal(nil)
		resp.Result = result
