type mockLSPServer struct {
	stdinR  *io.PipeReader
	stdoutW *io.PipeWriter
	done    chan struct{}
}

func newMockLSPServer() (
	clientStdin io.WriteCloser,
	clientStdout io.ReadCloser,
	srv *mockLSPServer,
) {
	srvStdinR, clientStdinW := io.Pipe()
	clientStdoutR, srvStdoutW := io.Pipe()
	srv = &mockLSPServer{
		stdinR:  srvStdinR,
		stdoutW: srvStdoutW,
		done:    make(chan struct{}),
	}
	go srv.serve()
	return clientStdinW, clientStdoutR, srv
}

func (s *mockLSPServer) serve() {
	defer close(s.done)
	br := bufio.NewReader(s.stdinR)
	for {
		contentLen, err := readHeaders(br)
		if err != nil {
			return
		}
		body := make([]byte, contentLen)
		if _, err := io.ReadFull(br, body); err != nil {
			return
		}
		var msg jsonrpcMessage
		if err := json.Unmarshal(body, &msg); err != nil {
			continue
		}
		if msg.ID == nil {
			continue
		}
		resp := s.handleRequest(msg)
		respBody, _ := json.Marshal(resp)
		header := fmt.Sprintf(
			"Content-Length: %d\r\n\r\n",
			len(respBody),
		)
		if _, err := io.WriteString(
			s.stdoutW, header,
		); err != nil {
			return
		}
		if _, err := s.stdoutW.Write(
			respBody,
		); err != nil {
			return
		}
	}
}

func (s *mockLSPServer) handleRequest(
	msg jsonrpcMessage,
) jsonrpcMessage {
	resp := jsonrpcMessage{
		JSONRPC: "2.0",
		ID:      msg.ID,
	}
	switch msg.Method {
	case "initialize":
		result, _ := json.Marshal(map[string]any{
			"capabilities": map[string]any{},
		})
		resp.Result = result
	case "shutdown":
		result, _ := json.Marshal(nil)
		resp.Result = result
	case "textDocument/hover":
		result, _ := json.Marshal(map[string]any{
			"contents": map[string]any{
				"kind":  "markdown",
				"value": "test hover",
			},
		})
		resp.Result = result
	case "textDocument/definition":
		result, _ := json.Marshal(
			[]semanticapi.Location{{
				URI: "file:///test/main.go",
				Range: semanticapi.Range{
					Start: semanticapi.Position{
						Line: 10, Character: 0,
					},
					End: semanticapi.Position{
						Line: 10, Character: 5,
					},
				},
			}},
		)
		resp.Result = result
	case "textDocument/references":
		result, _ := json.Marshal(
			[]semanticapi.Location{
				{
					URI: "file:///test/main.go",
					Range: semanticapi.Range{
						Start: semanticapi.Position{
							Line: 5, Character: 0,
						},
						End: semanticapi.Position{
							Line: 5, Character: 5,
						},
					},
				},
				{
					URI: "file:///test/main.go",
					Range: semanticapi.Range{
						Start: semanticapi.Position{
							Line: 15, Character: 0,
						},
						End: semanticapi.Position{
							Line: 15, Character: 5,
						},
					},
				},
			},
		)
		resp.Result = result
	case "workspace/symbol":
		result, _ := json.Marshal(
			[]semanticapi.SymbolInformation{{
				Name: "TestSymbol",
				Kind: semanticapi.SymbolKindFunction,
				Location: semanticapi.Location{
					URI: "file:///test/main.go",
				},
			}},
		)
		resp.Result = result
	case "textDocument/completion":
		result, _ := json.Marshal(map[string]any{
			"isIncomplete": false,
			"items": []map[string]any{{
				"label": "TestFunc",
				"kind":  3,
			}},
		})
		resp.Result = result
	default:
		result, _ := json.Marshal(nil)
		resp.Result = result
	}
	return resp
}

