func newTestManager(
	t *testing.T,
) (*Manager, *mockNotifications) {
	t.Helper()

	notif := &mockNotifications{}
	exec := &mockExecutor{}
	binPath := "/usr/local/bin/gopls"
	fs := &mockFileSystem{
		files: map[string]bool{
			binPath: true,
		},
	}
	pkg := &mockPkgManager{
		dirs: []string{"/usr/local/bin"},
	}

	mgr := New(Config{
		RootURI:       "file:///test",
		FileSystem:    fs,
		Executor:      exec,
		Notifications: notif,
		PkgManager:    pkg,
		MaxRetries:    2,
	})
	t.Cleanup(func() { _ = mgr.Close() })

	return mgr, notif
}

func openGoFile(
	t *testing.T,
	ctx context.Context,
	mgr *Manager,
	uri string,
