) {
	t.Helper()
	evURI, err := workspaceapi.ParseURI(uri)
	require.NoError(t, err)
	mgr.Handle(ctx, textapi.Event{
		Type:    textapi.EventTypeOpen,
		URI:     evURI,
		Content: content,
	})
}

