func testHandleOpen(t *testing.T) {
	mgr, _ := newTestManager(t)
	ctx := context.Background()
	openGoFile(t, ctx, mgr,
		"file:///test/main.go", "package main\n",
	)

	mgr.mu.Lock()
	langID := mgr.fileToLang["file:///test/main.go"]
	_, hasSrv := mgr.servers["go"]
	mgr.mu.Unlock()

	assert.Equal(t, "go", langID)
	assert.True(t, hasSrv)
}

