)

type realPkgManager struct {
	binDir string
}

func (p *realPkgManager) LibDir(
	_ context.Context, _ string,
) (iterator.Iterator[string], error) {
	return iterator.FromSlice(
		[]string{p.binDir},
	), nil
}

type realExecutor struct {
	procs map[workspaceapi.Pid]*exec.Cmd
	nextP workspaceapi.Pid
}

func newRealExecutor() *realExecutor {
	return &realExecutor{
		procs: make(map[workspaceapi.Pid]*exec.Cmd),
	}
}

func (e *realExecutor) Start(
	ctx context.Context, cmd workspaceapi.Cmd,
) (workspaceapi.Pid, error) {
	c := exec.CommandContext(ctx, cmd.Path, cmd.Args[1:]...)
	c.Dir = cmd.Dir
	c.Env = cmd.Env
	c.Stdin = cmd.Stdin
	c.Stdout = cmd.Stdout
	c.Stderr = cmd.Stderr

	if err := c.Start(); err != nil {
		return 0, err
	}

	e.nextP++
	pid := e.nextP
	e.procs[pid] = c

	if cmd.Watcher != nil {
		ch := cmd.Watcher.WatchProcess()
		if ch != nil {
			go func() {
				err := c.Wait()
				ch <- err
			}()
		}
	}

	return pid, nil
}

func (e *realExecutor) Signal(
	pid workspaceapi.Pid, sig syscall.Signal,
) error {
	c, ok := e.procs[pid]
	if !ok {
		return nil
	}
	return c.Process.Signal(sig)
}

func (e *realExecutor) Close() error {
	for _, c := range e.procs {
		if c.Process != nil {
			_ = c.Process.Kill()
		}
	}
	return nil
}

type realFileSystem struct{}

func (f *realFileSystem) URI(
	path string,
) (workspaceapi.URI, error) {
	return workspaceapi.CurrentUserHostURI(path)
}

func (f *realFileSystem) Stat(
	path string,
) (os.FileInfo, error) {
	return os.Stat(path)
}

func (f *realFileSystem) OpenFile(
	path string, flag int, mode os.FileMode,
) (workspaceapi.File, error) {
	return os.OpenFile(path, flag, mode)
}

func (f *realFileSystem) Remove(
	path string,
) error {
	return os.Remove(path)
}

func (f *realFileSystem) ReadDir(
	name string,
) ([]os.DirEntry, error) {
	return os.ReadDir(name)
}

func (f *realFileSystem) MkdirAll(
	path string, perm os.FileMode,
) error {
	return os.MkdirAll(path, perm)
}

func findGopls(t *testing.T) string {
	t.Helper()
	goplsBin, err := exec.LookPath("gopls")
	if err != nil {
		for _, p := range []string{
			filepath.Join(
				os.Getenv("HOME"),
				".rune", "bin", "gopls",
			),
			filepath.Join(
				os.Getenv("HOME"),
				"go", "bin", "gopls",
			),
		} {
			if _, err := os.Stat(p); err == nil {
				return p
			}
		}
		t.Skip("gopls not found, skipping e2e test")
	}
	return goplsBin
}

func setupTestWorkspace(t *testing.T) string {
	t.Helper()
	tmpDir := t.TempDir()

	testdataDir := filepath.Join(
		"testdata",
	)
	entries, err := os.ReadDir(testdataDir)
	require.NoError(t, err)
	for _, e := range entries {
		src := filepath.Join(testdataDir, e.Name())
		dst := filepath.Join(tmpDir, e.Name())
		data, err := os.ReadFile(src)
		require.NoError(t, err)
		require.NoError(t, os.WriteFile(
			dst, data, 0644,
		))
	}
	return tmpDir
}

func TestE2E(t *testing.T) {
	goplsBin := findGopls(t)
	tmpDir := setupTestWorkspace(t)

	executor := newRealExecutor()
	binDir := filepath.Dir(goplsBin)

	mgr := New(Config{
		RootURI:    "file://" + tmpDir,
		FileSystem: &realFileSystem{},
		Executor:   executor,
		PkgManager: &realPkgManager{binDir: binDir},
		MaxRetries: 1,
	})
	t.Cleanup(func() { _ = mgr.Close() })

	ctx := context.Background()

	mainPath := filepath.Join(tmpDir, "main.go")
	mainContent, err := os.ReadFile(mainPath)
	require.NoError(t, err)

	utilPath := filepath.Join(tmpDir, "util.go")
	utilContent, err := os.ReadFile(utilPath)
	require.NoError(t, err)

	mainURI := "file://" + mainPath
	utilURI := "file://" + utilPath

	mainWSURI, err := workspaceapi.ParseURI(mainURI)
	require.NoError(t, err)
	utilWSURI, err := workspaceapi.ParseURI(utilURI)
	require.NoError(t, err)

	mgr.Handle(ctx, textapi.Event{
		Type:    textapi.EventTypeOpen,
		URI:     mainWSURI,
		Content: string(mainContent),
	})
	mgr.Handle(ctx, textapi.Event{
		Type:    textapi.EventTypeOpen,
		URI:     utilWSURI,
		Content: string(utilContent),
	})

	// Wait for gopls to index.
	time.Sleep(3 * time.Second)

	tests := []struct {
		name string
		fn   func(t *testing.T)
	}{
		{
			name: "Hover",
			fn: func(t *testing.T) {
				result, err := mgr.Hover(ctx,
					semanticapi.HoverParams{
						TextDocument: semanticapi.TextDocumentIdentifier{
							URI: mainURI,
						},
						Position: semanticapi.Position{
							Line: 24, Character: 20,
						},
					},
				)
				require.NoError(t, err)
				require.NotNil(t, result)
			},
		},
		{
			name: "Definition",
			fn: func(t *testing.T) {
				locs, err := mgr.Definition(ctx,
					semanticapi.DefinitionParams{
						TextDocument: semanticapi.TextDocumentIdentifier{
							URI: mainURI,
						},
						Position: semanticapi.Position{
							Line: 36, Character: 15,
						},
					},
				)
				require.NoError(t, err)
				require.NotEmpty(t, locs)
			},
		},
		{
			name: "References",
			fn: func(t *testing.T) {
				locs, err := mgr.References(ctx,
					semanticapi.ReferenceParams{
						TextDocument: semanticapi.TextDocumentIdentifier{
							URI: mainURI,
						},
						Position: semanticapi.Position{
							Line: 29, Character: 6,
						},
						Context: semanticapi.ReferenceContext{
							IncludeDeclaration: true,
						},
					},
				)
				require.NoError(t, err)
				require.NotEmpty(t, locs)
			},
		},
		{
			name: "DocumentSymbol",
			fn: func(t *testing.T) {
				syms, err := mgr.DocumentSymbol(ctx,
					semanticapi.DocumentSymbolParams{
						TextDocument: semanticapi.TextDocumentIdentifier{
							URI: mainURI,
						},
					},
				)
				require.NoError(t, err)
				require.NotEmpty(t, syms)
			},
		},
		{
			name: "WorkspaceSymbol",
			fn: func(t *testing.T) {
				syms, err := mgr.WorkspaceSymbol(ctx,
					semanticapi.WorkspaceSymbolParams{
						Query: "Add",
					},
				)
				require.NoError(t, err)
				require.NotEmpty(t, syms)
				found := false
				for _, s := range syms {
					if s.Name == "Add" {
						found = true
						break
					}
				}
				assert.True(t, found,
					"expected to find Add symbol",
				)
			},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, tt.fn)
	}
}

