) (workspaceapi.Pid, error) {
	c := exec.CommandContext(ctx, cmd.Path, cmd.Args[1:]...)
	c.Dir = cmd.Dir
	c.Env = cmd.Env
	c.Stdin = cmd.Stdin
	c.Stdout = cmd.Stdout
	c.Stderr = cmd.Stderr

	if err := c.Start(); err != nil {
		return 0, err
	}

	e.nextP++
	pid := e.nextP
	e.procs[pid] = c

	if cmd.Watcher != nil {
		ch := cmd.Watcher.WatchProcess()
		if ch != nil {
			go func() {
				err := c.Wait()
				ch <- err
			}()
		}
	}

	return pid, nil
}

func (e *realExecutor) Signal(
	pid workspaceapi.Pid, sig syscall.Signal,
) error {
	c, ok := e.procs[pid]
	if !ok {
		return nil
	}
	return c.Process.Signal(sig)
}

func (e *realExecutor) Close() error {
	for _, c := range e.procs {
		if c.Process != nil {
			_ = c.Process.Kill()
		}
	}
	return nil
}

